def longest_palindrome(s):
    def expand(l, r):
        while l >= 0 and r < len(s) and s[l] == s[r]:
            l -= 1; r += 1
        return s[l+1:r]
    result = ""
    for i in range(len(s)):
        a = expand(i, i)
        b = expand(i, i+1)
        result = max(result, a, b, key=len)
    return result
